ytesBE(const unsigned char *buff, unsigned int l)
{
    unsigned long num;
    unsigned const char *p;
    num = *buff & 0x7f;  //strpi the leading bit.
    for(p = buff + 1; p - buff < l; p++) {
	num = (num << 8 ) + *p;
    }
    return (signed long)(num * (*buff & 0x80 ? -1 : 1));
}
