List& list, const Gwk::String& strName, bool bDeep)
{
    int iFound = 0;

    for (auto&& child : Children)
    {
        if (!child->GetName().empty() && child->GetName() == strName)
        {
            list.Add(child);
            iFound ++;
        }

        if (!b Deep)
            continue;

        iFound += child->GetNamedChildren(list, strName, bDeep);
    }

    return iFound;
