int num_of_digits(int64_t counter) // number of digits
{
int result = 1;
if (counter >= 100000000)
{
counter /= 100000000;
result += 8;
}
if (counter >= 10000)
{
 counter /= 10000;
result += 4;
}
if (counter >= 100)
{
counter /= 100;
result += 2;
}
if (counter >= 10)
return result + 1;
else
return result;

